import{_ as s,o as a,c as t,ae as i}from"./chunks/framework.BGHOrOyn.js";const u=JSON.parse('{"title":"Exposing Ports on Oracle Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/networking/oracle-vcn-docs/exposing-ports-on-oracle-cloud.md","filePath":"software-engineering/networking/oracle-vcn-docs/exposing-ports-on-oracle-cloud.md"}'),n={name:"software-engineering/networking/oracle-vcn-docs/exposing-ports-on-oracle-cloud.md"};function o(l,e,p,c,d,r){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="exposing-ports-on-oracle-cloud" tabindex="-1">Exposing Ports on Oracle Cloud <a class="header-anchor" href="#exposing-ports-on-oracle-cloud" aria-label="Permalink to &quot;Exposing Ports on Oracle Cloud&quot;">​</a></h1><p>I figured it out. The connectivity issue was due to Oracle&#39;s default use of iptables on all Oracle-provided images. Literally the very first thing I did when spinning up this instance was check <code>ufw</code>, presuming there were a few firewall restrictions in place. The <code>ufw</code> status was inactive, so I concluded the firewall was locally wide open. Because to my understanding both <code>ufw</code> and <code>iptables</code> look at the netfilter kernel firewall, and because <code>ufw</code> is the de facto (standard?) firewall solution on Ubuntu, I&#39;ve no idea why they concluded it made sense to use iptables in this fashion. Maybe just to standardize across all images?</p><p>I learned about the rules by running:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo iptables -L</span></span></code></pre></div><p>Then I saved the rules to a file so I could add the relevant ones back later:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sudo iptables-save &gt; ~/iptables-rules</span></span></code></pre></div><p>Then I ran these rules to effectively disable <code>iptables</code> by allowing all traffic through:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iptables -P INPUT ACCEPT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iptables -P OUTPUT ACCEPT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iptables -P FORWARD ACCEPT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iptables -F</span></span></code></pre></div><p>To clear all iptables rules at once, run this command:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">iptables --flush</span></span></code></pre></div><p>Anyway, hope this helps somebody else out because documentation on the matter is non-existent.</p><br>`,12)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
